import{_ as a}from"./Menu.edeb1320.js";import{u as r}from"./composables.4a9b2b71.js";import{r as e,a as n,e as u,b as o,f as i,o as d}from"./entry.787c95cd.js";const c=""+new URL("article-audit-ux.c3e29d3c.jpg",import.meta.url).href,p={class:"banniere"},m=i('<div class="margium-l marge-haute-l"><div class="espacium"><div class="colonnes"><div class="colonne"><h1>L&#39;audit UX</h1><div class="projettitre"></div> 20 janvier 2023 \xB7 2 min </div><div class="colonne"></div></div></div></div>',1),b=i('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p> Pour \xE9valuer l&#39;utilisabilit\xE9 d&#39;un dispositif, il existe 2 m\xE9thodes : le test utilisateur et l&#39;audit UX.<br> Cette derni\xE8re repose sur des crit\xE8res scientifiques appel\xE9s Heuristiques. Elle permet de d\xE9busquer les probl\xE8mes que peuvent rencontrer les utilisateurs et de proposer des solutions. L&#39;Audit UX est souvent utilis\xE9 pour \xE9tablir des &quot;Quick Fix&quot;, des point d&#39;am\xE9liorations faciles sur une interface pour obtenir de meilleurs taux de conversions. C&#39;est \xE9galement une mani\xE8re de v\xE9rifier une conception avant sa production. </p><h2>Les diff\xE9rente approches Heuristique</h2><p>Pour \xE9valuer une interface ou un dispositif, il existe une dizaine d&#39;approches d\u2019heuristiques diff\xE9rente, ici, nous allons voir les plus communes et les plus repr\xE9sentatives de leurs positionnements</p><ul><li><b>Bastien et scapin</b>, sont sans aucun doute les Heuristiques plus utilis\xE9, car elle r\xE9pondent au besoin g\xE9n\xE9rale d\u2019\xE9valuation de <b>l&#39;utilisabilit\xE9</b>.</li><li><b>Colombo &amp; Pasch&#39;s</b> Quand \xE0 elle, se focalise sur l&#39;\xE9valuations de <b>l\u2019efficacit\xE9</b> d&#39;un dispositif, elle peut \xEAtre utilis\xE9 dans les applications m\xE9tier</li><li><b>Arhippainen&#39;s</b> Vise a \xE9valuer davantage la <b>satisfaction</b></li></ul><h2>Les Heuristique de Bastien et Scapin</h2><ul><li><b>Guidage</b><ul><li><b>Regroupement et s\xE9paration</b> Es ce que les \xE9l\xE9ments qui se ressemble sont regroup\xE9 et s\xE9par\xE9 des autres ? (Les \xE9l\xE9ments de navigation sont s\xE9par\xE9s du contenu de la page, les fraises sont dans la rubrique fruits, les VTT ne sont pas avec les v\xE9lo de ville etc) </li><li> Es ce que l&#39;interface fait des <b>retours utilisateur</b> imm\xE9diat (message d&#39;erreur, annonce un temps de chargement etc.) </li><li><b>Lisibilit\xE9</b> (es ce que le fil d\u2019Ariane et visible, es ce que les text son suffisamment grand et contrast\xE9 pour \xEAtre lu etc.) </li><li> Incitant (es ce que les intitul\xE9 sont claire sur ce qu&#39;il regroupe, et ce que les nom des bouton et les icones sont explicite) </li></ul></li><li><b>Charge de travail</b></li><li><b>Contr\xF4le explicite</b></li><li><b>Adaptabilit\xE9</b></li><li><b>Gestion des erreurs</b></li><li><b>Homog\xE9n\xE9it\xE9 &amp; Coh\xE9rence</b></li><li><b>Signifiance des codes et d\xE9nominations</b></li><li><b>Compatibilit\xE9</b></li></ul><h2>Restitution et forme de l&#39;audit</h2><p>Un audit est un livrable, il est n\xE9cessaire qu&#39;il soit clair, concis, complet, d\xE9coupable et orient\xE9 solutions pour pouvoir \xEAtre trait\xE9 facilement par les \xE9quipes de design et de d\xE9veloppement.</p><img src="'+c+'" loading="lazy" alt="Exemple de pr\xE9sentation d&#39;audit UX"></div></div></article>',1),x={__name:"audit-ux",setup(v){const s=e("L'audit UX - Lucas Lacroix"),t=e("Pour \xE9valuer l'utilisabilit\xE9 d'un dispositif, il existe 2 m\xE9thodes : le test utilisateur et l'audit UX. Cette derni\xE8re repose sur des crit\xE8res scientifiques appel\xE9s Heuristiques. Elle permet de d\xE9busquer les probl\xE8mes que peuvent rencontrer les utilisateurs");return r({title:s,meta:[{name:"description",content:t}]}),(f,h)=>{const l=a;return d(),n("div",null,[u("div",p,[o(l),m]),b])}}};export{x as default};
